#include <iostream>
#include <string>
#include <sstream>

class Counter {
public:
    int count;

    Counter(int initial = 0) : count(initial) {}

    Counter& operator++() {
        ++count;
        return *this;
    }

    Counter operator--(int) {
        Counter temp = *this;
        --count;
        return temp;
    }

    int getCount() const {
        return count;
    }
};

int main() {
    std::stringstream ss;

    Counter c1(5);
    ss << "Initial c1: " << c1.getCount() << std::endl;

    ++c1;
    ss << "After ++c1: " << c1.getCount() << std::endl;

    c1--;
    ss << "After c1-- (original): " << c1.getCount() << std::endl;

    c1.count = 10;
    ss << "After direct c1.count = 10: " << c1.getCount() << std::endl;

    ++c1;
    ss << "After ++c1 (after direct modification): " << c1.getCount() << std::endl;

    Counter c2(0);
    ss << "Initial c2: " << c2.getCount() << std::endl;

    Counter temp_c2 = c2--;
    ss << "c2-- returned: " << temp_c2.getCount() << std::endl;
    ss << "After c2-- (original c2): " << c2.getCount() << std::endl;

    std::cout << ss.str();

    return 0;
}
